#include <iostream>
#include <string>
#include <vector>
#include <map>
#include <unordered_map>

// Packet structure
struct Packet {
    std::string type;
    float x, y, z; // player position
};

class Player {
public:
    std::string id;
    float x, y, z;

    void updatePosition(float newX, float newY, float newZ) {
        x = newX;
        y = newY;
        z = newZ;
    }
};

// Game server class
class Server {
private:
    int port;
    struct sockaddr_in address;
    int addrlen;
    int sockFd;

public:
    std::map<std::string, Player> players;

    void startServer(int port) {
        this->port = port;

        // Create a UDP socket
        if ((sockFd = socket(AF_INET, SOCK_DGRAM, 0)) < 0) {
            std::cerr << "Socket creation failed." << std::endl;
            exit(1);
        }

        address.sin_family = AF_INET;
        address.sin_addr.s_addr = INADDR_ANY;
        address.sin_port = htons(port);

        // Bind the socket to the port
        if (bind(sockFd, (struct sockaddr*)&address, sizeof(address)) < 0) {
            std::cerr << "Bind failed." << std::endl;
            exit(1);
        }

        addrlen = sizeof(address);
    }

    void broadcastPacket(const Packet& packet) {
        char buffer[1024];
        memset(buffer, 0, 1024);

        // Serialize the packet
        sprintf(buffer, "%s %f %f %f", packet.type.c_str(), packet.x, packet.y, packet.z);

        // Send the packet to all connected clients
        for (auto& player : players) {
            sendto(sockFd, buffer, strlen(buffer), 0, (struct sockaddr*)&player.second.address, sizeof(player.second.address));
        }
    }

    void handleClient(const std::string& data) {
        Packet packet;
        sscanf(data.c_str(), "%s %f %f %f", &packet.type[0], &packet.x, &packet.y, &packet.z);

        if (packet.type == "POSITION") {
            // Update player position
            auto player = players.find(packet.id);
            if (player != players.end()) {
                player->second.updatePosition(packet.x, packet.y, packet.z);
                broadcastPacket(Packet{"POSITION", packet.x, packet.y, packet.z});
            }
        } else if (packet.type == "SHOOT") {
            // Handle shooting mechanics
            auto player = players.find(packet.id);
            if (player != players.end()) {
                // Simulate bullet trajectory and collision detection
                std::cout << "Player " << packet.id << " has shot." << std::endl;
            }
        }
    }

    void run() {
        while (true) {
            char buffer[1024];
            memset(buffer, 0, 1024);

            // Receive a packet from a client
            recvfrom(sockFd, buffer, 1024, 0, (struct sockaddr*)&address, (socklen_t*)&addrlen);

            std::string data = buffer;

            // Handle the received packet
            handleClient(data);
        }
    }
};

int main() {
    Server server;
    server.startServer(12345); // Port 12345

    server.players["player1"] = Player{"player1", 0.0f, 0.0f, 0.0f};
    server.players["player2"] = Player{"player2", 10.0f, 10.0f, 0.0f};

    server.run();

    return 0;
}